/**
 * Calculates the sum of absolute differences in frequencies between characters and their mirrored counterparts.
 * @param {string} s The input string.
 * @returns {number} The total sum of absolute differences.
 */
function solve(s) {
    /**
     * Determines the mirror character for a given input character.
     * @param {string} char The character to mirror.
     * @returns {string} The mirrored character.
     */
    function getMirror(char) {
        const code = char.charCodeAt(0);

        // Handle lowercase letters ('a' through 'z')
        if (char >= 'a' && char <= 'z') {
            // 'a' is ASCII 97. Index = code - 97.
            const base = 'a'.charCodeAt(0);
            const index = code - base;
            // Mirror index: 25 - index (since a=0, z=25)
            const mirrorIndex = 25 - index;
            return String.fromCharCode(base + mirrorIndex);
        } 

        // Handle digits ('0' through '9')
        else if (char >= '0' && char <= '9') {
            // '0' is ASCII 48. Index = code - 48.
            const base = '0'.charCodeAt(0);
            const index = code - base;
            // Mirror index: 9 - index (since 0=0, 9=9)
            const mirrorIndex = 9 - index;
            return String.fromCharCode(base + mirrorIndex);
        }

        return null; // Should not happen based on constraints
    }

    // 1. Count frequencies of all characters in s
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    let totalDifference = 0;
    const processed = new Set();

    // 2. Iterate over unique characters and calculate the sum of differences
    for (const char of freq.keys()) {
        if (processed.has(char)) {
            continue;
        }

        const m = getMirror(char);

        // Frequency of char is guaranteed to exist and be > 0
        const freqC = freq.get(char);

        // Frequency of m might be 0 if m is not in s
        const freqM = freq.get(m) || 0;

        const difference = Math.abs(freqC - freqM);
        totalDifference += difference;

        // Mark both characters in the pair (char, m) as processed to prevent double counting
        processed.add(char);
        processed.add(m);
    }

    return totalDifference;
}

